export function nextGeneration(liveCells: Cell[]): Cell[] {
  const liveSet = new Set(liveCells.map(cellKey));
  const survivors = liveCells.filter((cell) => countLiveNeighbors(cell, liveSet) >= 2);

  const candidateMap = new Map<string, Cell>();
  for (const live of liveCells) {
    for (const neighbor of neighborsOf(live)) {
      const key = cellKey(neighbor);
      if (!liveSet.has(key)) candidateMap.set(key, neighbor);
    }
  }
  const births: Cell[] = [];
  for (const candidate of candidateMap.values()) {
    if (countLiveNeighbors(candidate, liveSet) === 3) births.push(candidate);
  }

  return [...survivors, ...births];
}

